import json

D = lambda i,t,s,e,n,c,nx: {"id":i,"text":t,"speaker":"我","avatar":"厂","score":s,"triggeredEvent":e,"historicalNote":n,"consequence":c,"nextActId":nx}
A = lambda i,t,k,tm,s,n,dls: {"id":i,"title":t,"isKeyAct":k,"timeMarker":tm,"sceneDescription":s,"npcDialogues":n,"dialogues":dls}
N = lambda sp,tx,av: {"speaker":sp,"text":tx,"avatar":av}

acts = []

# === 第1幕：创业之初 ===
acts.append(A("act-1","创业之初",False,"1765年",
"1765年的英国曼彻斯特，纺织业方兴未艾。你继承了父亲留下的小型作坊，站在轰鸣的织机旁思考着工厂的未来。哈格里夫斯刚刚发明了珍妮纺纱机，整个行业都在酝酿着巨大变革。",
[N("老工头约瑟夫","老板，听说哈格里夫斯的珍妮机一次能纺八根纱线，产量能翻好几倍。","约"),N("商人威廉","现在棉纱供不应求，价格一路上涨。只要你能扩大生产，我包销你所有产品。","威")],
[D("d1","我要立刻订购珍妮纺纱机，扩大生产规模，抢占市场先机。",92,"你果断订购了十台珍妮纺纱机，产量迅速提升。几个月后，你的棉纱占领了附近市场，工厂规模扩大了一倍。","珍妮纺纱机由哈格里夫斯于1765年发明，最初一次能纺8根纱线，后经改进可纺80根。这一发明标志着工业革命的开始。","产量大增，市场扩张","act-2"),
D("d2","先观望一下，看看别人用珍妮机的效果再说，不急着投资。",72,"你选择了观望。半年后，采用珍妮机的工厂产量远超于你，你失去了部分市场份额，但工厂仍能维持经营。","工业革命初期，新技术的推广速度各不相同。保守的工厂主因循守旧，逐渐被敢于创新的竞争者淘汰。","错失先机，勉强维持","act-2"),
D("d3","我要亲自去拜访哈格里夫斯，看看能不能获得独家代理权。",85,"你专程拜访了哈格里夫斯，经过谈判获得了在兰开夏郡的独家代理权。你的工厂成为当地最早使用珍妮机的企业。","哈格里夫斯是英国兰开夏郡的纺织工匠，他发明的珍妮纺纱机以他女儿的名字命名。这一发明没有申请专利，很快被广泛仿制。","获得独家代理权","act-2"),
D("d4","技术革新风险太大，我还是维持现状，稳扎稳打比较好。",65,"你决定维持传统生产方式。然而不到一年，周边工厂纷纷采用新机器，你的产品在价格和数量上都失去了竞争力。","工业革命是一场深刻的社会变革，拒绝新技术的企业很快被淘汰。到18世纪末，英国的手工纺织业基本被机器生产取代。","竞争力下降，订单减少","act-1b"),
D("d5","我打算在河边建一座水力纺纱厂，利用水力驱动更大的机器。",88,"你在曼彻斯特附近的欧文河畔找到了一块合适的土地，开始规划建设水力纺纱厂。虽然投资巨大，但你预见到这是未来的方向。","阿克莱特于1769年发明水力纺纱机，并于1771年在克罗姆福德建立了第一座水力纺纱厂，工厂制度由此诞生。","规划水力纺纱厂","act-2"),
D("d6","我要去伦敦考察，了解最新的技术和市场动态。",80,"你前往伦敦考察了两个月，走访了各大工厂和发明家。回来时你不仅带回了新技术信息，还结识了几位重要的商业伙伴。","18世纪中后期，伦敦是英国的商业和金融中心，各地的工厂主经常前往伦敦获取信息和融资。","开阔眼界，结识伙伴","act-2"),
D("d7","先改进现有设备，在传统织机上做些改良，成本低见效快。",70,"你对现有织机进行了一些小改良，产量略有提升。但与珍妮机相比，差距仍然明显，你只能在低端市场维持份额。","工业革命中，渐进式改良与革命性创新并存。虽然革命性的发明影响更大，但无数小的技术改进也共同推动了生产力发展。","小幅改良，效果有限","act-2"),
D("d8","我要招募一批熟练工匠，提高产品质量，走高端路线。",78,"你高薪聘请了几位熟练工匠，专门生产高质量的纺织品。虽然产量不大，但利润丰厚，你的工厂在高端市场赢得了声誉。","工业革命初期，高质量的手工产品仍有市场。但随着机器产品质量的不断提高，手工纺织品的市场空间逐渐被压缩。","高端路线，利润丰厚","act-2"),
D("d9","我打算把工厂卖掉，转行做别的生意，纺织业竞争太激烈了。",62,"你卖掉了工厂，转行做了纺织品贸易。虽然避开了生产环节的激烈竞争，但看着昔日同行的工厂越做越大，你心中不免有些后悔。","工业革命时期，确实有一些传统工厂主选择退出生产领域，转向贸易或金融。但从长远来看，工业生产创造了巨大的财富和机遇。","转行贸易，错失机遇","act-1b")]))

# === 第1b幕：困境重重 ===
acts.append(A("act-1b","困境重重",False,"1766年",
"你的工厂陷入了困境。采用新机器的竞争对手以更低的价格抢占市场，你的订单持续减少。工人们也因为收入下降而人心惶惶。作为工厂主，你必须找到扭转局面的方法。",
[N("账房先生托马斯","老板，这个月的订单又减少了三成。再这样下去，我们最多撑半年就得关门。","托"),N("老工头约瑟夫","工人们都在担心失业，干活也没精打采的。再不想办法，恐怕要出乱子。","约")],
[D("d1","立刻订购珍妮纺纱机，全面升级设备，哪怕借债也要跟上时代。",90,"你下定决心，抵押了房产贷款订购了一批珍妮纺纱机。经过几个月的改造，工厂产量大幅提升，终于扭转了颓势。","工业革命中，许多工厂主通过借贷进行技术升级。英国的银行体系和资本市场为工业发展提供了资金支持。","贷款升级，扭转颓势","act-2"),
D("d2","削减工人工资，降低成本，先熬过这段困难时期再说。",63,"你宣布削减工人工资。工人们虽然不满，但为了生计只能接受。然而生产积极性大幅下降，产品质量也出现了问题。","工业革命初期，工人工资普遍很低，工作条件恶劣。工厂主为了降低成本经常削减工资，这也是后来工人运动兴起的重要原因之一。","工资削减，积极性下降","act-2"),
D("d3","我去联系更大的批发商，薄利多销，靠量取胜。",72,"你找到了几位大批发商，以更低的价格换取了更大的订单。虽然利润微薄，但工厂总算运转了起来。","工业革命时期，大规模生产和大规模销售相伴而生。批发商和零售商阶层崛起，形成了覆盖全国乃至全球的商业网络。","薄利多销，勉强维持","act-2"),
D("d4","转型生产特种纺织品，避开与大工厂的正面竞争。",82,"你决定转型生产高端特种纺织品，如刺绣蕾丝等。虽然产量不大，但利润率很高，工厂在细分市场找到了生存空间。","工业革命时期，并非所有手工行业都被机器取代。一些需要复杂技艺的高端产品仍然依赖手工生产。","转型成功，细分市场","act-2"),
D("d5","把工厂搬到农村去，那里土地和劳动力都更便宜。",68,"你把工厂搬到了偏远的乡村。虽然成本降低了，但交通不便、信息闭塞，经营状况并没有太大改善。","工业革命初期，很多工厂建在农村河流附近以利用水力。但随着蒸汽机的普及，工厂逐渐向城市集中。","搬迁农村，改善有限","act-2"),
D("d6","我要去请教那些成功的工厂主，学习他们的经验。",85,"你放下身段，向几位成功的工厂主请教。他们分享了技术改良和管理经验，你回来后应用这些方法，工厂状况逐渐好转。","工业革命时期，工厂主之间形成了各种协会和社团，互相交流技术和管理经验。这种知识传播机制加速了技术创新的扩散。","学习经验，逐渐好转","act-2"),
D("d7","解雇一批工人，剩下的人增加工作量，压缩人力成本。",60,"你解雇了近一半工人，留下的人被迫承担更多工作。工人们怨声载道，几个熟练工干脆辞职去了别的工厂。","工业革命时期，工人权益缺乏保障，解雇是工厂主常用的手段。但过度剥削也会导致工人反抗，破坏生产秩序。","裁员减员，人心涣散","act-2"),
D("d8","申请破产保护，把损失降到最低，以后东山再起。",66,"你申请了破产，卖掉了设备偿还债务。虽然失去了工厂，但你保住了住房和一些积蓄。这段经历让你对工业有了更深刻的认识。","工业革命时期，商业竞争激烈，企业破产是常有的事。英国相对完善的破产制度为失败者提供了翻身的机会。","破产收场，等待时机","act-2"),
D("d9","我要和别的小工厂联合起来，共同对抗大工厂的竞争。",76,"你联络了几家小工厂，组成了一个松散的联盟。你们联合采购原材料，共享市场信息，整体竞争力有所提升。","工业革命时期，各种形式的企业联合不断出现。早期的卡特尔、辛迪加等垄断组织就是在竞争中逐渐形成的。","联合抗敌，竞争力提升","act-2")]))

print(f"已生成 {len(acts)} 幕")
